INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Use the dish or drink name followed by a dash and key ingredients or style. Keep it scannable — this appears in the table row."},"content":{"tips":"Write a short, appetizing description. Focus on ingredients, preparation, and dietary information. Keep it under a few sentences."},"formatting":["Bold: dish name and price-relevant details","Bullet lists: ingredients, dietary labels (GF, V, VG, DF)","Italics: preparation notes or chef recommendations","Paragraphs: keep to 1-2 short paragraphs max"],"avoid":["Long-form content — menus should be scannable","Missing allergen or dietary information","Vague descriptions without specific ingredients"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":5,"max":100},"content":{"min":1,"max":2000},"sourceAi":{"min":1,"max":100}}', datetime('now'));
